mapper.select:
SELECT
FROM user_favorite uf INNER JOIN fund_info f ON f.fund_id = uf.fund_id LEFT JOIN fund_company c ON c.company_id = f.company_id LEFT JOIN s ON s.fund_id = f.fund_id LEFT JOIN pm ON pm.fund_id = f.fund_id LEFT JOIN ( SELECT fund_id, string_agg(manager_name, '、' ORDER BY rn) AS manager_name FROM ( SELECT fmr.fund_id, fm.manager_name, ROW_NUMBER() OVER (PARTITION BY fmr.fund_id ORDER BY fmr.is_current DESC, fmr.relation_id) AS rn FROM fund_manager_relation fmr INNER JOIN fund_manager fm ON fm.manager_id = fmr.manager_id ) ranked WHERE rn <= 2 GROUP BY fund_id ) cm ON cm.fund_id = f.fund_id WHERE uf.user_id = #{userId}
AND uf.favorite_group = #{favoriteGroup}
ORDER BY uf.created_time DESC, uf.favorite_id DESC
